import axios from "axios";
import Swal from "sweetalert2";

const instance = axios.create({
  baseURL: "http://localhost:8080",
  headers: { "Content-Type": "application/json" },
});

const ToastError = (title, message) =>
    Swal.fire({ icon: "error", title, text: message });

const ToastWarning = (title, message) =>
    Swal.fire({ icon: "warning", title, text: message });

const ToastSuccess = (title, message) =>
    Swal.fire({ icon: "success", title, text: message, timer: 2000, showConfirmButton: false });

function getToken() {
  return localStorage.getItem("token");
}

export function saveToken(token) {
  localStorage.setItem("token", token);
}

export function removeToken() {
  localStorage.removeItem("token");
}

export function isAuthenticated() {
  return !!getToken();
}

instance.interceptors.request.use(
    (config) => {
      const token = getToken();
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
        console.log(`[AXIOS] TOKEN ENVIADO EN: ${config.method.toUpperCase()} ${config.url}`);
      } else {
        console.log(`[AXIOS] SIN TOKEN EN: ${config.method.toUpperCase()} ${config.url}`);
      }
      return config;
    },
    (error) => Promise.reject(error)
);

instance.interceptors.response.use(
    (response) => response,
    (error) => {
      if (!error.response) {
        ToastError("Error de conexión", "No se pudo conectar con el servidor.");
        return Promise.reject(error);
      }

      const { status } = error.response;
      const url = error.config?.url || '';

      // Si es 401 y NO es endpoint de auth, limpiar y redirigir
      if (status === 401 && !url.includes('/api/auth/')) {
        removeToken();
        localStorage.removeItem("user");
        localStorage.removeItem("userData");

        // Solo redirigir si no estamos ya en login
        if (window.location.pathname !== "/login") {
          ToastError("Sesión expirada", "Por favor inicia sesión nuevamente.");
          setTimeout(() => {
            window.location.href = "/login";
          }, 1000);
        }
        return Promise.reject(error);
      }

      if (status === 403) {
        ToastWarning("Acceso denegado", "No tienes permisos para esta acción.");
      } else if (status === 400) {
        const data = error.response.data;
        if (data && typeof data === "object") {
          const key = Object.keys(data)[0];
          const val = data[key];
          ToastWarning("Datos incorrectos", Array.isArray(val) ? val[0] : String(val));
        } else {
          ToastWarning("Datos incorrectos", "Verifica la información ingresada.");
        }
      } else if (status === 404) {
        ToastWarning("No encontrado", "El recurso solicitado no existe.");
      } else if (status === 500) {
        ToastError("Error del servidor", "Ocurrió un error. Inténtalo más tarde.");
      }

      return Promise.reject(error);
    }
);

export default {
  async doDelete(url, data) { return await instance.delete(url, { data }); },
  async doPost(url, data, config = {}) { return await instance.post(url, data, config); },
  async doGet(url, config = {}) { return await instance.get(url, config); },
  async doPut(url, data, config = {}) { return await instance.put(url, data, config); },
  async doPostFile(url, data) {
    return await instance.post(url, data, { headers: { "Content-Type": "multipart/form-data" } });
  },
  async doPutFile(url, data) {
    return await instance.put(url, data, { headers: { "Content-Type": "multipart/form-data" } });
  },
  ToastSuccess,
  ToastError,
  ToastWarning,
};

import axios from "axios";
import Swal from "sweetalert2";

// Configurar base URL - IMPORTANTE: debe ser el backend
const API_BASE_URL = "http://localhost:8080";

const instance = axios.create({
  baseURL: API_BASE_URL,
  timeout: 10000,
  headers: { 
    "Content-Type": "application/json",
  },
});

const ToastError = (title, message) =>
    Swal.fire({ icon: "error", title, text: message });

const ToastWarning = (title, message) =>
    Swal.fire({ icon: "warning", title, text: message });

const ToastSuccess = (title, message) =>
    Swal.fire({ icon: "success", title, text: message, timer: 2000, showConfirmButton: false });

function getToken() {
  const token = localStorage.getItem("token") || localStorage.getItem("accessToken");
  return token;
}

export function saveToken(token) {
  if (!token) return;
  localStorage.setItem("token", token);
  localStorage.setItem("accessToken", token);
}

export function removeToken() {
  localStorage.removeItem("token");
  localStorage.removeItem("accessToken");
  localStorage.removeItem("user");
  localStorage.removeItem("userData");
}

export function isAuthenticated() {
  const token = getToken();
  return !!token && token.length > 0;
}

// Interceptor de REQUEST - Agregar token
instance.interceptors.request.use(
    (config) => {
      const token = getToken();

      // Loguear petición
      const method = config.method.toUpperCase();
      const path = config.url;

      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
        console.log(`[API] ${method} ${path} - Token enviado`);
      } else {
        console.log(`[API] ${method} ${path} - Sin token`);
      }

      return config;
    },
    (error) => {
      console.error("[API] Error en request:", error);
      return Promise.reject(error);
    }
);

// Interceptor de RESPONSE - Manejar errores
instance.interceptors.response.use(
    (response) => {
      const { status } = response;
      console.log(`[API] Respuesta exitosa - Status: ${status}`);
      return response;
    },
    (error) => {
      // Error sin respuesta del servidor
      if (!error.response) {
        console.error("[API] Error de conexión:", error.message);
        ToastError("Error de conexión", "No se pudo conectar con el servidor.");
        return Promise.reject(error);
      }

      const { status, data } = error.response;
      const url = error.config?.url || '';
      const method = error.config?.method?.toUpperCase() || 'UNKNOWN';

      console.error(`[API] Error ${status} en ${method} ${url}:`, data);

      // Error 401 - No autenticado/Token expirado
      if (status === 401) {
        // Si NO es endpoint de auth, limpiar y redirigir
        if (!url.includes('/api/auth/')) {
          console.warn("[API] Token inválido o expirado - Limpiando sesión");
          removeToken();

          // Solo redirigir si no estamos ya en login
          if (window.location.pathname !== "/login") {
            ToastError("Sesión expirada", "Por favor inicia sesión nuevamente.");
            setTimeout(() => {
              window.location.href = "/login";
            }, 800);
          }
        }
        return Promise.reject(error);
      }

      // Error 403 - Acceso denegado
      if (status === 403) {
        ToastWarning("Acceso denegado", "No tienes permisos para esta acción.");
        return Promise.reject(error);
      }

      // Error 400 - Datos incorrectos
      if (status === 400) {
        const message = data?.message || data?.error || "Verifica la información ingresada.";
        ToastWarning("Datos incorrectos", message);
        return Promise.reject(error);
      }

      // Error 404 - No encontrado
      if (status === 404) {
        ToastWarning("No encontrado", "El recurso solicitado no existe.");
        return Promise.reject(error);
      }

      // Error 500 - Error del servidor
      if (status === 500) {
        ToastError("Error del servidor", "Ocurrió un error. Inténtalo más tarde.");
        return Promise.reject(error);
      }

      // Otros errores
      ToastError("Error", data?.message || "Ocurrió un error inesperado");
      return Promise.reject(error);
    }
);

export default {
  async doDelete(url, data) { return await instance.delete(url, { data }); },
  async doPost(url, data, config = {}) { return await instance.post(url, data, config); },
  async doGet(url, config = {}) { return await instance.get(url, config); },
  async doPut(url, data, config = {}) { return await instance.put(url, data, config); },
  async doPostFile(url, data) {
    return await instance.post(url, data, { headers: { "Content-Type": "multipart/form-data" } });
  },
  async doPutFile(url, data) {
    return await instance.put(url, data, { headers: { "Content-Type": "multipart/form-data" } });
  },
  ToastSuccess,
  ToastError,
  ToastWarning,
};

import axios from '../config/AxiosConfig';

export const orderService = {
  // Crear orden
  createOrder(orderData) {
    return axios.doPost('/api/orders', orderData);
  },

  // Obtener orden por ID
  getOrderById(id) {
    return axios.doGet(`/api/orders/${id}`);
  },

  // Listar órdenes
  listOrders(customerId = null) {
    const params = customerId ? { customerId } : {};
    return axios.doGet('/api/orders', { params });
  }
};

import axios from '../config/AxiosConfig';

export const orderService = {
  // Crear orden
  createOrder(orderData) {
    return axios.doPost('/api/orders', orderData);
  },

  // Obtener orden por ID
  getOrderById(id) {
    return axios.doGet(`/api/orders/${id}`);
  },

  // Listar órdenes
  listOrders(customerId = null) {
    const params = customerId ? { customerId } : {};
    return axios.doGet('/api/orders', { params });
  },

  // Actualizar estado de orden (Admin)
  updateOrderStatus(id, status) {
    return axios.doPut(`/api/orders/${id}/status`, null, {
      params: { status }
    });
  },

  // Cancelar orden (Admin)
  cancelOrder(id) {
    return axios.doDelete(`/api/orders/${id}`);
  }
};
